const body = $input.first().json.body || $input.first().json;
const query = $input.first().json.query;

if (query?.['hub.mode'] === 'subscribe') {
  return [{ json: { isVerification: true, challenge: query['hub.challenge'] } }];
}

const entry = body?.entry?.[0];
const changes = entry?.changes?.[0];
const value = changes?.value;

if (!value?.messages && value?.statuses) {
  return [{ json: { skip: true, reason: 'status_update' } }];
}

const message = value?.messages?.[0];
const contact = value?.contacts?.[0];

if (!message) {
  return [{ json: { skip: true, reason: 'no_message' } }];
}

let buttonId = '';
let listId = '';
let userInput = '';

if (message.type === 'interactive') {
  if (message.interactive?.type === 'button_reply') {
    buttonId = message.interactive.button_reply.id || '';
    userInput = buttonId;
  } else if (message.interactive?.type === 'list_reply') {
    listId = message.interactive.list_reply.id || '';
    userInput = listId;
  }
} else if (message.type === 'text') {
  userInput = message.text?.body?.trim() || '';
} else if (message.type === 'image' || message.type === 'document') {
  userInput = 'media_received';
  buttonId = 'media_received';
}

return [{
  json: {
    skip: false,
    phone: message.from,
    name: contact?.profile?.name || 'Patient',
    messageId: message.id,
    messageType: message.type,
    userInput,
    rawText: message.text?.body || '',
    buttonId,
    listId,
    timestamp: message.timestamp,
  }
}];

const skipCheck = $('Skip Check').first().json;
const sessionArr = $input.all().map(r => r.json);
const validSessions = sessionArr.filter(s => s.patient_phone);
validSessions.sort((a, b) => new Date(b.last_activity) - new Date(a.last_activity));
const session = validSessions.length > 0 ? validSessions[0] : null;
const userInput = skipCheck.userInput || '';

let currentStep = 'main_menu';
if (userInput === 'book_appointment') currentStep = 'book_appointment';
else if (userInput.startsWith('dept_')) currentStep = 'select_department';
else if (userInput.startsWith('doc_')) currentStep = 'select_doctor';
else if (userInput.startsWith('date_')) currentStep = 'select_date';
else if (userInput.startsWith('time_')) currentStep = 'select_time';
else if (userInput === 'confirm_booking') currentStep = 'confirm_booking';
else if (userInput === 'cancel_booking') currentStep = 'main_menu';
else if (userInput === 'my_appointments') currentStep = 'my_appointments';
else if (userInput.startsWith('cancel_')) currentStep = 'cancel_appointment';
else if (userInput === 'hospital_location') currentStep = 'hospital_location';
else if (userInput === 'hospital_timings') currentStep = 'hospital_timings';
else if (userInput === 'payment_methods') currentStep = 'payment_methods';
else if (userInput === 'payment_cash') currentStep = 'payment_cash';
else if (userInput === 'payment_meezan') currentStep = 'payment_meezan';
else if (userInput.length > 4 && session?.current_step === 'payment_meezan') currentStep = 'save_payment_meezan';

let parsedContext = {};
try {
  const ctx = session?.context;
  parsedContext = typeof ctx === 'string' ? JSON.parse(ctx) : (ctx || {});
} catch(e) { parsedContext = {}; }

if (userInput.startsWith('doc_')) {
  parsedContext.doctor_id = userInput;
  parsedContext.appointment_date = '';
}
if (userInput.startsWith('date_')) {
  parsedContext.appointment_date = userInput.replace('date_', '');
}

return [{ json: {
  phone: skipCheck.phone,
  patient_phone: skipCheck.phone,
  name: skipCheck.name,
  userInput: userInput,
  buttonId: skipCheck.buttonId,
  listId: skipCheck.listId,
  rawText: skipCheck.rawText,
  messageType: skipCheck.messageType,
  current_step: currentStep,
  context: parsedContext,
  sessionId: session?.session_id || null,
  hasSession: !!session
}}];

