const mergeState = $('Merge State').first().json;
const userInput = mergeState.userInput || '';
const docId = userInput.replace('doc_', '');
const context = mergeState.context || {};

const availabilityData = $input.all().map(r => r.json);
const availableDays = availabilityData.map(a => a.day_of_week);

const dates = [];
const today = new Date();
for (let i = 1; i <= 30 && dates.length < 7; i++) {
  const d = new Date(today);
  d.setDate(today.getDate() + i);
  const day = d.getDay();

  if (availableDays.includes(day)) {
    const label = d.toLocaleDateString('en-US', { 
      weekday: 'short', month: 'short', day: 'numeric' 
    });
    const val = d.toISOString().split('T')[0];
    dates.push({ 
      id: 'date_' + val, 
      title: label, 
      description: 'Available' 
    });
  }
}

return [{ json: {
  patient_phone: mergeState.patient_phone,
  name: mergeState.name,
  doctorId: docId,
  context: {
    dept_id: context.dept_id,
    dept_name: context.dept_name,
    dept_slug: context.dept_slug,
    doctor_id: docId
  },
  rows: dates
}}];

