const mergeState = $('Merge State').first().json;
const userInput = mergeState.userInput || '';
const context = typeof mergeState.context === 'string'
  ? JSON.parse(mergeState.context)
  : mergeState.context || {};

const selectedDate = userInput.startsWith('date_')
  ? userInput.replace('date_', '')
  : (context.appointment_date || '');

// Get booked slots
const bookedData = $('Get Booked Slots').all().map(r => r.json);
const bookedTimes = bookedData.map(b => b.appointment_time?.substring(0, 5));

const slotDuration = 20;
const bufferMinutes = 5;
const totalInterval = slotDuration + bufferMinutes;

const slots = [];
const startHour = 9;
const endHour = 17;

for (let h = startHour; h < endHour; h++) {
  for (let m = 0; m < 60; m += totalInterval) {
    if (h * 60 + m + slotDuration > endHour * 60) break;
    const timeStr = String(h).padStart(2, '0') + ':' + String(m).padStart(2, '0');
    if (!bookedTimes.includes(timeStr)) {
      const ampm = h >= 12 ? 'PM' : 'AM';
      const displayHour = h > 12 ? h - 12 : h === 0 ? 12 : h;
      const displayMin = String(m).padStart(2, '0');
      slots.push({
        id: 'time_' + timeStr,
        title: `🕐 ${displayHour}:${displayMin} ${ampm}`,
        description: '20 min slot'
      });
    }
  }
}

// Max 10 slots (WhatsApp limit)
const finalSlots = slots.slice(0, 10);

return [{
  json: {
    patient_phone: mergeState.patient_phone,
    name: mergeState.name,
    selectedDate,
    context,
    rows: finalSlots.length > 0
      ? finalSlots
      : [{ id: 'no_slots', title: '❌ No slots available', description: 'Please choose another date' }]
  }
}];

